    <view class="tab-item" @click="navTo('prepare')">备课</view>
    <view class="tab-item active">会员卡</view> <!-- 这里会员卡设为 active -->
    <view class="tab-item" @click="navTo('mine')">我的</view>
  </view>
  
  
