<script setup>
import { ref } from 'vue' // ✅ 必须导入 ref，否则脚本会报错中断

const currentDays = ref(0)

// 1. 打开支付选择菜单
const openPayMenu = (days) => {
  currentDays.value = days
  
  uni.showActionSheet({
    itemList: ['微信支付', '支付宝支付'],
    success: function (res) {
      if (res.tapIndex === 0) {
        startPay('wxpay')
      } else {
        startPay('alipay')
      }
    },
    fail: function (res) {
      console.log(res.errMsg);
    }
  });
}

// 2. 发起支付请求
const startPay = (provider) => {
  uni.showLoading({ title: '创建订单...' });
  
  // 请求后端生成订单参数
  uni.request({
    url: 'http://127.0.0.1:8000/api/pay/create_order', // 记得改IP
    method: 'POST',
    data: {
      days: currentDays.value,
      provider: provider
    },
    success: (res) => {
      uni.hideLoading();
      if (res.data.code === 200) {
        const orderInfo = res.data.orderInfo;
        
        // --- 模拟测试环境逻辑 (如果你没填Key，走这里) ---
        // 注意：后端返回的是 simulation_alipay_string，这里判断改为 includes('simulation')
        if (typeof orderInfo === 'string' && orderInfo.includes('simulation')) {
           uni.showModal({
             title: '模拟支付',
             content: '检测到未配置真实支付Key，是否模拟支付成功？',
             success: (mockRes) => {
               if(mockRes.confirm) mockSuccess()
             }
           })
           return;
        }
        
        // --- 真实支付环境逻辑 (uni.requestPayment) ---
        uni.requestPayment({
          provider: provider, 
          orderInfo: orderInfo, 
          success: function (res) {
            mockSuccess() 
          },
          fail: function (err) {
            uni.showToast({ title: '支付取消或失败', icon: 'none' });
          }
        });
        
      } else {
        uni.showToast({ title: '订单创建失败', icon: 'none' });
      }
    }
  });
}

// 3. 支付成功后的处理
const mockSuccess = () => {
  uni.request({
    url: `http://127.0.0.1:8000/api/pay/mock_success?days=${currentDays.value}`,
    method: 'POST',
    success: () => {
      uni.showToast({ title: '开通成功！', icon: 'success' });
      setTimeout(() => {
        // 跳转到“我的”页面
        uni.reLaunch({ url: '/pages/mine/mine' }); 
      }, 1500);
    }
  })
}

// 4. ✅ 补全导航函数 (否则点击底部导航会报错)
const navTo = (page) => {
  const routes = {
    'index': '/pages/index/index',
    'prepare': '/pages/prepare/prepare',
    'mine': '/pages/mine/mine'
  }
  uni.reLaunch({ url: routes[page] });
}
</script>
